class Solution {
public:
    int makeTheIntegerZero(int num1, int num2) {
        int operations = 0;
        while (num1 > 0) {
            for (int i = 0; i <= 60; ++i) {
                if (2 * i + num2 <= num1) {
                    num1 -= 2 * i + num2;
                    operations++;
                    break;
                }
            }
            if (num1 <= 0) {
                break;
            }
        }
        return num1 == 0 ? operations : -1;
    }
};
